1825	static void compare_one_tensor(st_db *db, const gguf_file *tmpl, const output_context *out_ctx,
1826	                               const params *p, const imatrix_store *imatrix) {
1827	    int idx = hmap_get(&tmpl->tensor_map, p->compare_tensor);
1828	    if (idx < 0) {
1829	        fprintf(stderr, "error: tensor not found in template: %s\n", p->compare_tensor);
1830	        exit(1);
1831	    }
1832	    fprintf(stderr, "regenerating %s as %s\n",
1833	            p->compare_tensor, ds4q_type_name(out_ctx->tensors[idx].type));
1834	    byte_buf generated = generate_tensor(db, p->compare_tensor, &tmpl->tensors[idx],
1835	                                         out_ctx->tensors[idx].type, p->n_experts, p->n_threads, imatrix);
1836	    gguf_file ref = load_gguf_metadata(p->compare_gguf);
1837	    byte_buf reference = read_gguf_tensor_data(&ref, p->compare_gguf, p->compare_tensor);
1838	    printf("tensor: %s\n", p->compare_tensor);
1839	    printf("type: %s\n", ds4q_type_name(out_ctx->tensors[idx].type));
1840	    printf("generated_bytes: %zu\n", generated.size);
1841	    printf("reference_bytes: %zu\n", reference.size);
1842	    printf("generated_fnv1a64: %016" PRIx64 "\n", fnv1a64_bytes(generated.data, generated.size));
1843	    printf("reference_fnv1a64: %016" PRIx64 "\n", fnv1a64_bytes(reference.data, reference.size));
1844	    size_t mismatches = 0;
1845	    size_t first = SIZE_MAX;
1846	    const size_t n = generated.size < reference.size ? generated.size : reference.size;
1847	    for (size_t i = 0; i < n; i++) {
1848	        if (generated.data[i] != reference.data[i]) {
1849	            if (first == SIZE_MAX) first = i;
1850	            mismatches++;
1851	        }
1852	    }
1853	    if (generated.size != reference.size) {
1854	        if (first == SIZE_MAX) first = n;
1855	        mismatches += generated.size > reference.size ? generated.size - reference.size : reference.size - generated.size;
1856	    }
1857	    if (!mismatches) {
1858	        printf("byte_compare: OK\n");
1859	    } else {
1860	        printf("byte_compare: FAIL mismatches=%zu first=%zu\n", mismatches, first);
1861	    }
1862	    free(generated.data);
1863	    free(reference.data);
1864	    free_gguf_file(&ref);
1865	}
