1090	static byte_buf f32_to_type(const float *src, int64_t n, ds4q_type type, int64_t ncols, const float *imat) {
1091	    if (ncols <= 0 || n % ncols != 0) die("bad ncols for tensor conversion");
1092	    byte_buf out = {0};
1093	    if (type == DS4Q_TYPE_F32) {
1094	        out.size = (size_t)n * sizeof(float);
1095	        out.data = xmalloc(out.size);
1096	        memcpy(out.data, src, out.size);
1097	        return out;
1098	    }
1099	    if (type == DS4Q_TYPE_F16) {
1100	        out.size = (size_t)n * sizeof(uint16_t);
1101	        out.data = xmalloc(out.size);
1102	        ds4q_f32_to_f16_row(src, (uint16_t *)out.data, n);
1103	        return out;
1104	    }
1105	    if (type == DS4Q_TYPE_BF16) {
1106	        out.size = (size_t)n * sizeof(uint16_t);
1107	        out.data = xmalloc(out.size);
1108	        ds4q_f32_to_bf16_row(src, (uint16_t *)out.data, n);
1109	        return out;
1110	    }
1111	    if (!ds4q_can_quantize(type)) die("unsupported quant target type");
1112	    if (ncols % ds4q_block_size(type) != 0) die("ncols is not divisible by quant block size");
1113	    const int64_t nrows = n / ncols;
1114	    out.size = (size_t)nrows * ds4q_row_size(type, ncols);
1115	    out.data = xmalloc(out.size);
1116	
1117	    float *synthetic = NULL;
1118	    const float *im_ptr = imat;
1119	    if (!im_ptr && ds4q_requires_imatrix(type)) {
1120	        synthetic = xcalloc((size_t)ncols, sizeof(float));
1121	        for (int64_t r = 0; r < nrows; r++) {
1122	            const float *row = src + (size_t)r * (size_t)ncols;
1123	            for (int64_t c = 0; c < ncols; c++) synthetic[c] += row[c] * row[c];
1124	        }
1125	        im_ptr = synthetic;
1126	    }
1127	    size_t written = ds4q_quantize_chunk(type, src, out.data, 0, nrows, ncols, im_ptr);
1128	    free(synthetic);
1129	    if (written != out.size) die("ds4q_quantize_chunk wrote unexpected byte count");
1130	    return out;
1131	}
