1133	static byte_buf i64_to_i32(const st_value *src) {
1134	    if (strcmp(src->dtype, "I64") != 0) die("expected I64 source for I32 tensor");
1135	    const int64_t n = value_nelements(src);
1136	    if (src->nbytes != (size_t)n * sizeof(int64_t)) die("bad I64 byte size");
1137	    byte_buf out = { .size = (size_t)n * sizeof(int32_t), .data = xmalloc((size_t)n * sizeof(int32_t)) };
