1469	    g.n_kv = read_u64_le_fp(fp, "GGUF KV count");
1470	    g.alignment = DS4_GGUF_DEFAULT_ALIGNMENT;
1471	    byte_span *kv_keep = xcalloc((size_t)g.n_kv, sizeof(kv_keep[0]));
1472	    uint64_t n_kv_keep = 0;
1473	
1474	    off_t kv_start = ftello(fp);
1475	    if (kv_start < 0) die("GGUF ftell failed");
1476	    for (uint64_t i = 0; i < g.n_kv; i++) {
1477	        off_t rec_start = ftello(fp);
1478	        if (rec_start < 0 || rec_start < kv_start) die("GGUF ftell failed");
1479	        char *key = read_gguf_string_fp(fp);
1480	        uint32_t type = read_u32_le_fp(fp, "GGUF KV type");
1481	        if (strcmp(key, "general.alignment") == 0 && type == GGUF_TYPE_UINT32) {
1482	            uint32_t a = read_u32_le_fp(fp, "GGUF alignment");
1483	            if (a) g.alignment = a;
1484	        } else if (strcmp(key, "deepseek4.expert_count") == 0 && type == GGUF_TYPE_UINT32) {
1485	            uint32_t n = read_u32_le_fp(fp, "GGUF expert count");
1486	            if (n <= (uint32_t)INT_MAX) g.n_experts = (int)n;
1487	        } else if (strcmp(key, "deepseek4.expert_count") == 0 && type == GGUF_TYPE_UINT64) {
1488	            uint64_t n = read_u64_le_fp(fp, "GGUF expert count");
1489	            if (n <= (uint64_t)INT_MAX) g.n_experts = (int)n;
1490	        } else {
1491	            skip_gguf_value_fp(fp, type);
1492	        }
1493	        off_t rec_end = ftello(fp);
1494	        if (rec_end < 0 || rec_end < rec_start) die("GGUF ftell failed");
1495	
1496	        /*
1497	         * Template GGUFs may already carry imatrix provenance from a previous
1498	         * quantization.  Drop those keys and write the current run's keys later,
1499	         * otherwise the output can contain duplicate GGUF metadata with stale
1500	         * and new values.
1501	         */
1502	        if (!is_imatrix_kv_key(key)) {
1503	            kv_keep[n_kv_keep++] = (byte_span){
1504	                .start = (size_t)(rec_start - kv_start),
1505	                .end = (size_t)(rec_end - kv_start),
1506	            };
1507	        }
1508	        free(key);
1509	    }
1510	    off_t tensor_start = ftello(fp);
1511	    if (tensor_start < 0 || tensor_start < kv_start) die("GGUF ftell failed");
1512	    size_t kv_full_len = (size_t)(tensor_start - kv_start);
1513	    uint8_t *kv_full = xmalloc(kv_full_len);
1514	    if (fseeko(fp, kv_start, SEEK_SET) != 0) die("GGUF seek failed");
1515	    if (kv_full_len && fread(kv_full, 1, kv_full_len, fp) != kv_full_len) die("GGUF KV read failed");
1516	
1517	    for (uint64_t i = 0; i < n_kv_keep; i++) g.kv_raw_len += kv_keep[i].end - kv_keep[i].start;
1518	    g.kv_raw = xmalloc(g.kv_raw_len);
1519	    size_t kv_pos = 0;
1520	    for (uint64_t i = 0; i < n_kv_keep; i++) {
1521	        size_t n = kv_keep[i].end - kv_keep[i].start;
1522	        memcpy(g.kv_raw + kv_pos, kv_full + kv_keep[i].start, n);
1523	        kv_pos += n;
1524	    }
1525	    g.n_kv = n_kv_keep;
1526	    free(kv_full);
1527	    free(kv_keep);
1528	    if (fseeko(fp, tensor_start, SEEK_SET) != 0) die("GGUF seek failed");
1529	
1530	    g.tensors = xcalloc((size_t)g.n_tensors, sizeof(g.tensors[0]));
1531	    for (uint64_t i = 0; i < g.n_tensors; i++) {
1532	        tensor_meta *t = &g.tensors[i];
1533	        t->name = read_gguf_string_fp(fp);
1534	        t->n_dims = (int)read_u32_le_fp(fp, "GGUF tensor rank");
1535	        if (t->n_dims < 1 || t->n_dims > DS4Q_MAX_DIMS) die("bad GGUF tensor rank");
1536	        for (int j = 0; j < t->n_dims; j++) t->ne[j] = (int64_t)read_u64_le_fp(fp, "GGUF tensor dim");
1537	        t->type = (ds4q_type)read_u32_le_fp(fp, "GGUF tensor type");
1538	        t->old_offset = read_u64_le_fp(fp, "GGUF tensor offset");
1539	        t->size = tensor_nbytes(t->type, t->ne, t->n_dims);
1540	    }
1541	    off_t meta_end = ftello(fp);
1542	    if (meta_end < 0) die("GGUF ftell failed");
1543	    g.data_offset = ds4q_pad((size_t)meta_end, g.alignment);
1544	    char **keys = xmalloc((size_t)g.n_tensors * sizeof(keys[0]));
1545	    for (uint64_t i = 0; i < g.n_tensors; i++) keys[i] = g.tensors[i].name;
1546	    hmap_build(&g.tensor_map, keys, (int)g.n_tensors);
1547	    free(keys);
1548	    fclose(fp);
1549	    return g;
1550	}
