1552	static byte_buf read_gguf_tensor_data(const gguf_file *g, const char *path, const char *name) {
1553	    int idx = hmap_get(&g->tensor_map, name);
1554	    if (idx < 0) {
1555	        fprintf(stderr, "error: tensor not found in GGUF: %s\n", name);
1556	        exit(1);
