638	static float e4m3fn_to_f32(uint8_t x) {
639	    const uint8_t abs = x & 0x7f;
640	    const bool sign = (x & 0x80) != 0;
641	    if (abs == 0) return sign ? -0.0f : 0.0f;
642	    if (abs == 0x7f) return 0.0f;
643	    const int exp = (x >> 3) & 0x0f;
644	    const int man = x & 0x07;
645	    float value = exp == 0 ? ldexpf((float)man, -9)
646	                           : ldexpf(1.0f + (float)man / 8.0f, exp - 7);
647	    return sign ? -value : value;
648	}
