683	static float *dequant_fp8_weight(const st_value *w, const st_value *scale, int64_t *n_out) {
684	    if (strcmp(w->dtype, "F8_E4M3") != 0 || strcmp(scale->dtype, "F8_E8M0") != 0) die("bad FP8 weight/scale dtype");
685	    if (w->n_dims != 2 || scale->n_dims != 2) die("FP8 tensor must be 2D");
686	    const int64_t out_dim = w->shape[0];
687	    const int64_t in_dim = w->shape[1];
688	    const int64_t block_out = 128;
689	    const int64_t block_in = 128;
690	    if (out_dim % block_out || in_dim % block_in) die("FP8 dims are not divisible by 128");
691	    const int64_t scale_rows = out_dim / block_out;
692	    const int64_t scale_cols = in_dim / block_in;
693	    if (scale->shape[0] != scale_rows || scale->shape[1] != scale_cols) die("FP8 scale shape mismatch");
694	    float *out = xmalloc((size_t)out_dim * (size_t)in_dim * sizeof(float));
695	    for (int64_t ob = 0; ob < scale_rows; ob++) {
696	        for (int64_t ib = 0; ib < scale_cols; ib++) {
697	            const float s = e8m0_to_f32(scale->data[(size_t)ob * (size_t)scale_cols + (size_t)ib]);
698	            for (int64_t r = 0; r < block_out; r++) {
699	                const int64_t row = ob * block_out + r;
700	                const size_t base = (size_t)row * (size_t)in_dim + (size_t)ib * (size_t)block_in;
701	                for (int64_t c = 0; c < block_in; c++) {
702	                    out[base + (size_t)c] = e4m3fn_to_f32(w->data[base + (size_t)c]) * s;
703	                }
704	            }
705	        }
706	    }
707	    if (n_out) *n_out = out_dim * in_dim;
708	    return out;
709	}
