711	static float *dequant_fp4_weight(const st_value *w, const st_value *scale, int64_t *n_out) {
712	    static const float fp4_table[16] = {
713	        0.0f,  0.5f,  1.0f,  1.5f,  2.0f,  3.0f,  4.0f,  6.0f,
714	        0.0f, -0.5f, -1.0f, -1.5f, -2.0f, -3.0f, -4.0f, -6.0f,
715	    };
716	    if (strcmp(w->dtype, "I8") != 0 || strcmp(scale->dtype, "F8_E8M0") != 0) die("bad FP4 weight/scale dtype");
717	    if (w->n_dims != 2 || scale->n_dims != 2) die("FP4 tensor must be 2D");
718	    const int64_t out_dim = w->shape[0];
719	    const int64_t packed_in = w->shape[1];
720	    const int64_t in_dim = packed_in * 2;
721	    if (in_dim % 32) die("FP4 in_dim is not divisible by 32");
722	    const int64_t n_blocks = in_dim / 32;
723	    if (scale->shape[0] != out_dim || scale->shape[1] != n_blocks) die("FP4 scale shape mismatch");
724	    float *out = xmalloc((size_t)out_dim * (size_t)in_dim * sizeof(float));
725	    for (int64_t r = 0; r < out_dim; r++) {
726	        for (int64_t b = 0; b < n_blocks; b++) {
727	            const float s = e8m0_to_f32(scale->data[(size_t)r * (size_t)n_blocks + (size_t)b]);
728	            const size_t wbase = ((size_t)r * (size_t)n_blocks + (size_t)b) * 16;
729	            const size_t obase = (size_t)r * (size_t)in_dim + (size_t)b * 32;
730	            for (int64_t j = 0; j < 16; j++) {
731	                const uint8_t q = w->data[wbase + (size_t)j];
732	                out[obase + (size_t)(2*j + 0)] = fp4_table[q & 0x0f] * s;
733	                out[obase + (size_t)(2*j + 1)] = fp4_table[(q >> 4) & 0x0f] * s;
734	            }
735	        }
736	    }
737	    if (n_out) *n_out = out_dim * in_dim;
738	    return out;
739	}
